final:
module RefModule(
    input clk,
    input rst,
    input enable,
    input up_down,
    output reg [3-1:1-1] q
);

always @(posedge clk) begin
    if (rst)
        q <= 3'b000;
    else if (enable) begin
        if (up_down)
            q <= q + 1;
        else
            q <= q - 1;
    end
end

endmodule
